import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import Login from "./components/LoginPage/Login";
import ForgotPassword from "./components/ForgotPassword/ForgotPassword";
import VerifyOtpPage from "./components/VerifyOtpPage/VerifyOtpPage";
import ResetPassword from "./components/ResetPassword/ResetPassword";
import UserDashboard from "./components/UserDashBoard/UserDashBoard";
import StaffDashboard from "./components/StaffDashBoard/StaffDashBoard"; 
import Profile from "./components/Profile/Profile";// Import StaffDashboard

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Login />} />
        <Route path="/forgot-password" element={<ForgotPassword />} />
        <Route path="/verify-otp" element={<VerifyOtpPage />} />
        <Route path="/reset-password" element={<ResetPassword />} />
        <Route path="/userdashboard" element={<UserDashboard />} />
        <Route path="/staffdashboard" element={<StaffDashboard />} /> {/* Added StaffDashboard route */}
        <Route path="/profile" element={<Profile />} />
      </Routes>
    </Router>
  );
}

export default App;
